import { useState, useEffect } from 'react';
import useLiveBots from '../hooks/useLiveBots';
import usePositions from '../hooks/usePositions';
import useChartData from '../hooks/useChartData';
import useRisk from '../hooks/useRisk';
import useIsMobile from '../hooks/useIsMobile';
import { apiPost } from '../utils/api';
import InfoTooltip from '../components/InfoTooltip';
import LoadingState from '../components/LoadingState';
import { RAW as HEX, fonts } from '../tokens';
import { getApiBase } from '../utils/platform';
import s from './TraderExecution.module.css';

const C = HEX;
const mono = fonts.mono;
const body = fonts.ui;

function fmt$(v) {
  if (v == null || typeof v !== 'number' || !isFinite(v)) return '--';
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2 }).format(v);
}

function Panel({ style, label, children }) {
  return (
    <div className={s.panel} style={style}>
      {label && <div className={s.panelHeader}>{label}</div>}
      <div className={s.panelBody}>{children}</div>
    </div>
  );
}

// ─── One-Click Trade Entry ──────────────────────────────────────────────────

function OneClickEntry({ bots }) {
  const [symbol, setSymbol] = useState('');
  const [side, setSide] = useState('BUY');
  const [qty, setQty] = useState(100);
  const [orderType, setOrderType] = useState('MKT');
  const [limitPrice, setLimitPrice] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [result, setResult] = useState(null);

  const handleSubmit = async () => {
    if (!symbol) return;
    setSubmitting(true);
    setResult(null);
    const payload = {
      symbol: symbol.toUpperCase(),
      side,
      quantity: qty,
      order_type: orderType,
      limit_price: orderType === 'LMT' ? parseFloat(limitPrice) : undefined,
    };
    const res = await apiPost('/exec/intent', payload);
    setResult(res?.error ? { ok: false, msg: res.error } : { ok: true, msg: 'Intent logged' });
    setSubmitting(false);
    setTimeout(() => setResult(null), 3000);
  };

  return (
    <div className={s.formCol}>
      <div>
        <span className={s.formLabel}>Symbol</span>
        <input className={s.formInput} value={symbol} onChange={e => setSymbol(e.target.value.toUpperCase())} placeholder="AAPL" />
      </div>

      <div className={s.sideRow}>
        {['BUY', 'SELL'].map(sd => (
          <button
            key={sd}
            onClick={() => setSide(sd)}
            className={s.sideBtn}
            style={{
              background: side === sd ? (sd === 'BUY' ? C.green : C.red) : undefined,
              color: side === sd ? '#fff' : undefined,
            }}
          >
            {sd}
          </button>
        ))}
      </div>

      <div>
        <span className={s.formLabel}>Quantity</span>
        <input className={s.formInput} type="number" value={qty} onChange={e => setQty(+e.target.value)} min={1} />
      </div>

      <div>
        <span className={s.formLabel}>Order Type</span>
        <div className={s.orderTypeRow}>
          {['MKT', 'LMT', 'STP'].map(t => (
            <button
              key={t}
              onClick={() => setOrderType(t)}
              className={orderType === t ? s.orderTypeBtnActive : s.orderTypeBtn}
            >
              {t}
            </button>
          ))}
        </div>
      </div>

      {orderType === 'LMT' && (
        <div>
          <span className={s.formLabel}>Limit Price</span>
          <input className={s.formInput} type="number" step="0.01" value={limitPrice} onChange={e => setLimitPrice(e.target.value)} />
        </div>
      )}

      <div className={s.submitArea}>
        <button
          onClick={handleSubmit}
          disabled={submitting || !symbol}
          className={s.submitBtn}
          style={{
            cursor: submitting ? 'wait' : 'pointer',
            background: side === 'BUY' ? C.green : C.red,
            opacity: submitting || !symbol ? 0.5 : 1,
          }}
        >
          {submitting ? 'SUBMITTING...' : `${side} ${qty} ${symbol || '---'}`}
        </button>
        {result && (
          <div className={s.submitResult} style={{ color: result.ok ? C.green : C.red }}>
            {result.msg}
          </div>
        )}
      </div>
    </div>
  );
}

